cd /tmp && node -e '
const loadConfig = require("/Users/elon/work/fable-profile/eval/comparison/runs/2026-06-18/ambiguous/A1/k1/AMB1-robust/config_loader.js");
const fs = require("fs");

// 1. valid config
fs.writeFileSync("/tmp/good.json", JSON.stringify({a:1}));
console.log("valid:", JSON.stringify(loadConfig("/tmp/good.json")));

// 2. missing file, no fallback -> clear throw
try { loadConfig("/tmp/nope.json"); } catch (e) { console.log("missing throws:", e.message); }

// 3. missing file, with fallback -> returns fallback (no crash)
console.log("missing fallback:", JSON.stringify(loadConfig("/tmp/nope.json", {default:true})));

// 4. trailing comma / bad JSON, no fallback -> clear throw
fs.writeFileSync("/tmp/bad.json", "{\"a\":1,}");
try { loadConfig("/tmp/bad.json"); } catch (e) { console.log("bad JSON throws:", e.message); }

// 5. bad JSON with fallback -> returns fallback
console.log("bad JSON fallback:", JSON.stringify(loadConfig("/tmp/bad.json", {})));

// 6. bad path arg
try { loadConfig(null); } catch (e) { console.log("bad arg throws:", e.message); }
'

